          new SubSchema({
            schema,
            formattedPath: formattedPath.prepend(pathHead),
            transformedPath: transformedPath.prepend(pathHead)
          })
      )
    }
    case 'anyOf': {
      return schema.elements.map(element => findSubSchemas(element, path)).flat()
